UPDATE course SET name=#{name}, description=#{description}, teacher_id=#{teacherId}, hours=#{hours}, fee=#{fee},
target_grade=#{targetGrade}, subject=#{subject}, teach_mode=#{teachMode}, location=#{location},
valid_start=#{validStart}, valid_end=#{validEnd}, class_time_desc=#{classTimeDesc},
max_students=#{maxStudents}, enrolled_count=#{enrolledCount}, suitable_age=#{suitableAge}, highlights=#{highlights}, status=#{status}
WHERE id = #{id}
